const axios = require('axios');
const axiosRetry = require('axios-retry');

const client = axios.create({ timeout: 5000 });
axiosRetry(client, {
  retries: 3,
  retryDelay: axiosRetry.exponentialDelay,
  retryCondition: (error) =>
    axiosRetry.isNetworkOrIdempotentRequestError(error) ||
    error.code === 'ECONNABORTED'
});

const BASE_URL = 'https://api.openweathermap.org/data/2.5';

async function getCurrentWeather(city) {
  const apiKey = process.env.OPENWEATHER_API_KEY;
  if (!apiKey) throw new Error('OPENWEATHER_API_KEY not set');

  const response = await client.get(`${BASE_URL}/weather`, {
    params: { q: city, appid: apiKey, units: 'metric' }
  });

  const data = response.data;
  return {
    city: data.name, country: data.sys.country,
    temp: data.main.temp, feelsLike: data.main.feels_like,
    humidity: data.main.humidity, description: data.weather[0].description,
    icon: data.weather[0].icon, windSpeed: data.wind.speed
  };
}

module.exports = { getCurrentWeather };

